import React from 'react';
import { FiCheckCircle } from 'react-icons/fi';

const About = () => {
  return (
    <section id="about" className="section">
      <div className="container">
        <div className="section-heading">
          <span className="eyebrow">Profile</span>
          <h2>Engineering Delivery With Field-Aware Judgment</h2>
        </div>
        <div className="about-layout">
          <p>
            Civil and project engineer with experience across infrastructure delivery, site coordination,
            structural documentation, procurement support, and construction-phase controls. Known for
            translating technical requirements into clear scopes, buildable details, and coordinated
            schedules for multidisciplinary teams.
          </p>
          <ul className="credential-list">
            <li><FiCheckCircle aria-hidden="true" /> Construction documentation and coordination</li>
            <li><FiCheckCircle aria-hidden="true" /> Site inspections, QA/QC, and progress reporting</li>
            <li><FiCheckCircle aria-hidden="true" /> AutoCAD, Revit, Civil 3D, MS Project, and Bluebeam</li>
          </ul>
        </div>
      </div>
    </section>
  );
};

export default About;
